/**
 * MapViewCompat — Cross-platform map wrapper.
 *
 * - Native (iOS/Android): Re-exports react-native-maps components.
 * - Web: Renders a styled placeholder since react-native-maps has no web support.
 *
 * Import from THIS module instead of 'react-native-maps' directly.
 */
import { Platform } from 'react-native';

// On native, re-export everything from react-native-maps.
// On web, provide stub components that render gracefully.

let MapView: any;
let Marker: any;
let Circle: any;
let Polyline: any;
let PROVIDER_GOOGLE: any;

if (Platform.OS === 'web') {
  // ── Web stubs ────────────────────────────────────────────────────────────────
  const React = require('react');
  const { View, Text, StyleSheet } = require('react-native');

  const webStyles = StyleSheet.create({
    container: {
      flex: 1,
      backgroundColor: '#E8F5F3',
      borderRadius: 16,
      justifyContent: 'center',
      alignItems: 'center',
      borderWidth: 1,
      borderColor: '#E5E7EB',
      borderStyle: 'dashed',
      minHeight: 200,
    },
    icon: {
      fontSize: 48,
      marginBottom: 12,
    },
    title: {
      fontSize: 16,
      fontWeight: '700',
      color: '#115C55',
      marginBottom: 4,
    },
    subtitle: {
      fontSize: 13,
      color: '#6B7280',
      textAlign: 'center',
    },
  });

  MapView = React.forwardRef((props: any, ref: any) => {
    return React.createElement(
      View,
      { style: [webStyles.container, props.style], ref },
      React.createElement(Text, { style: webStyles.icon }, '🗺️'),
      React.createElement(Text, { style: webStyles.title }, 'Map Preview'),
      React.createElement(
        Text,
        { style: webStyles.subtitle },
        'Interactive map available on mobile'
      ),
      props.children
    );
  });
  MapView.displayName = 'MapView';

  // Marker / Circle / Polyline: render nothing on web
  Marker = (_props: any) => null;
  Marker.displayName = 'Marker';

  Circle = (_props: any) => null;
  Circle.displayName = 'Circle';

  Polyline = (_props: any) => null;
  Polyline.displayName = 'Polyline';

  PROVIDER_GOOGLE = null;
} else {
  // ── Native: use the real library ─────────────────────────────────────────────
  const maps = require('react-native-maps');
  MapView = maps.default;
  Marker = maps.Marker;
  Circle = maps.Circle;
  Polyline = maps.Polyline;
  PROVIDER_GOOGLE = maps.PROVIDER_GOOGLE;
}

export default MapView;
export { Marker, Circle, Polyline, PROVIDER_GOOGLE };
